import { useEffect, useState } from "react"
import { Division, ISOString, Multiplication, checkIsNumber, getSessionUser, isEqualNumber } from "../../Components/functions"
import { Button, Card, CardContent, IconButton } from "@mui/material"
import FilterableTable, { createCol } from "../../Components/filterableTable2"
import { fetchLink } from "../../Components/fetchComponent"
import Select from 'react-select';
import { customSelectStyles } from "../../Components/tablecolumn";
import { Delete, Remove } from "@mui/icons-material"

const initialStockJournalInfoValues = {
    STJ_Id: '',
    ST_Inv_Id: '',
    Journal_no: '',

    Branch_Id: '',
    Stock_Journal_date: ISOString(),
    Stock_Journal_Bill_type: 'MATERIAL INWARD',
    Stock_Journal_Voucher_type: '',
    Invoice_no: '',
    Narration: '',
    Trip_No: '',
    Created_by: '',
    altered_by: '',

    Start_Time: '',
    End_Time: '',

    Vehicle_Start_KM: '',
    Vehicle_End_KM: '',
}

const initialSoruceValue = {
    SJD_Id: '',
    STJ_Id: '',
    Sour_Item_Id: '',
    Sour_Item_Name: '',
    Sour_Goodown_Id: '',
    Sour_Batch_Lot_No: '',
    Sour_Qty: '',
    Sour_Unit_Id: '',
    Sour_Unit: '',
    Sour_Rate: '',
    Sour_Amt: '',
}

const initialDestinationValue = {
    SJD_Id: '',
    STJ_Id: '',
    Dest_Item_Id: '',
    Dest_Item_Name: '',
    Dest_Goodown_Id: '',
    Dest_Batch_Lot_No: '',
    Dest_Qty: '',
    Dest_Unit_Id: '',
    Dest_Unit: '',
    Dest_Rate: '',
    Dest_Amt: '',
}

const initialStaffInvolvedValue = {
    STJ_Id: '',
    S_Id: '',
    Staff_Id: '',
    Staff_Name: '',
    Staff_Type_Id: '',
}

const StockJournalCreate = () => {
    const [baseData, setBaseData] = useState({
        products: [],
        branch: [],
        godown: [],
        voucherType: [],
        uom: [],
        staff: [],
    });
    const [stockJorunalInfo, setStockJorunalInfo] = useState(initialStockJournalInfoValues);
    const [sourceInput, setSourceInput] = useState(initialSoruceValue);
    const [destinationInput, setDestinationInput] = useState(initialDestinationValue);
    const [staffInvolvedInput, setStaffInvolvedInput] = useState(initialStaffInvolvedValue);

    const [sourceList, setSourceList] = useState([]);
    const [destinationList, setDestinationList] = useState([]);
    const [staffInvolvedList, setStaffInvolvedList] = useState([]);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [
                    branchResponse,
                    productsResponse,
                    godownLocationsResponse,
                    voucherTypeResponse,
                    uomResponse,
                    staffResponse
                ] = await Promise.all([
                    fetchLink({ address: `masters/branch/dropDown` }),
                    fetchLink({ address: `masters/products` }),
                    fetchLink({ address: `dataEntry/godownLocationMaster` }),
                    fetchLink({ address: `purchase/voucherType` }),
                    fetchLink({ address: `masters/uom` }),
                    fetchLink({ address: `dataEntry/costCenter` })
                ]);

                const branchData = branchResponse.success ? branchResponse.data : [];
                const productsData = productsResponse.success ? productsResponse.data : [];
                const godownLocations = godownLocationsResponse.success ? godownLocationsResponse.data : [];
                const voucherType = voucherTypeResponse.success ? voucherTypeResponse.data : [];
                const uomData = uomResponse.success ? uomResponse.data : [];
                const staffData = staffResponse.success ? staffResponse.data : [];

                setBaseData((pre) => ({
                    ...pre,
                    products: productsData,
                    branch: branchData,
                    godown: godownLocations,
                    voucherType: voucherType,
                    uom: uomData,
                    staff: staffData,
                }));
            } catch (e) {
                console.error("Error fetching data:", e);
            }
        };

        fetchData();
    }, []);

    const changeSelectedObjects = (rowIndex, key, value) => {
        setSourceList((prev) => {
            return prev.map((item, index) => {
                if (isEqualNumber(index, rowIndex)) {
                    switch (key) {
                        case 'Sour_Item_Id': {
                            const updatedValue = parseInt(value || 0);
                            const newItem = { ...item, Sour_Item_Id: updatedValue };
                            newItem.Sour_Item_Name = baseData.products?.find(pro =>
                                isEqualNumber(pro?.Product_Id, updatedValue)
                            )?.Product_Name ?? 'Not available';
                            return newItem;
                        }
                        case 'Sour_Unit_Id': {
                            const updatedValue = parseInt(value || 0);
                            const newItem = { ...item, Sour_Unit_Id: updatedValue };
                            newItem.Sour_Unit = baseData.uom?.find(uom =>
                                isEqualNumber(uom?.Unit_Id, updatedValue)
                            )?.Units ?? 'Not available';
                            return newItem;
                        }
                        case 'Sour_Qty': {
                            const updatedValue = parseFloat(value || 0);
                            const newItem = { ...item, Sour_Qty: updatedValue };
                            if (item.Sour_Rate) {
                                newItem.Sour_Amt = Multiplication(item.Sour_Rate, updatedValue);
                            } else if (item.Sour_Amt) {
                                newItem.Sour_Rate = Division(item.Sour_Amt, updatedValue);
                            } else {
                                newItem.Sour_Amt = '';
                                newItem.Sour_Rate = '';
                            }
                            return newItem;
                        }
                        case 'Sour_Rate': {
                            const updatedValue = parseFloat(value || 0);
                            const newItem = { ...item, Sour_Rate: updatedValue };
                            if (item.Sour_Qty) {
                                newItem.Sour_Amt = Multiplication(updatedValue, item.Sour_Qty);
                            } else if (item.Sour_Amt) {
                                newItem.Sour_Qty = Division(item.Sour_Amt, updatedValue);
                            } else {
                                newItem.Sour_Amt = '';
                                newItem.Sour_Qty = '';
                            }
                            return newItem;
                        }
                        case 'Sour_Amt': {
                            const updatedValue = parseFloat(value || 0);
                            const newItem = { ...item, Sour_Amt: updatedValue };
                            if (checkIsNumber(item.Sour_Qty)) {
                                newItem.Sour_Rate = Division(updatedValue, item.Sour_Qty);
                            } else if (checkIsNumber(item.Sour_Rate)) {
                                newItem.Sour_Qty = Division(updatedValue, item.Sour_Rate);
                            } else {
                                newItem.Sour_Rate = '';
                                newItem.Sour_Qty = '';
                            }
                            return newItem;
                        }
                        default:
                            return { ...item, [key]: value };
                    }
                }
                return item;
            });
        });
    };

    // conso

    return (
        <>
            <Card>
                <CardContent sx={{ minHeight: '80vh' }}>
                    <form onSubmit={e => {
                        e.preventDefault();
                        console.log("Submit", sourceList);
                    }}>
                        <div className="row ">
                            {/* Staff involved Info */}
                            <div className="col-xxl-2 col-lg-3 col-md-4 p-2">
                                <div className="border p-2" style={{ minHeight: '30vh', height: '100%' }}>
                                    <div className="d-flex align-items-center flex-wrap mb-2 border-bottom pb-2">
                                        <h6 className="flex-grow-1 m-0">Staff Involved</h6>
                                        <Button
                                            variant="outlined"
                                            color="primary"
                                            type="button"
                                            onClick={() => setStaffInvolvedList([...staffInvolvedList, { ...initialStaffInvolvedValue }])}
                                        >Add</Button>
                                    </div>
                                    <table className="table table-bordered">
                                        <thead>
                                            <tr>
                                                <th className="fa-13">Sno</th>
                                                <th className="fa-13">Staff Name</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {staffInvolvedList.map((row, index) => (
                                                <tr key={index}>
                                                    <td className='fa-13 vctr text-center'>{index + 1}</td>
                                                    <td className='fa-13 w-100'>
                                                        <Select
                                                            value={{ value: row?.Staff_Id, label: row?.Staff_Name }}
                                                            onChange={e => setStaffInvolvedList((prev) => {
                                                                return prev.map((item, ind) => {
                                                                    if (isEqualNumber(ind, index)) {
                                                                        return {
                                                                            ...item,
                                                                            Staff_Id: e.value,
                                                                            Staff_Name: e.label
                                                                        }
                                                                    }
                                                                    return item;
                                                                });
                                                            })}
                                                            options={
                                                                [...baseData.staff.filter(fil => (
                                                                    staffInvolvedList.findIndex(st => (
                                                                        isEqualNumber(st.Staff_Id === fil.Cost_Center_Id) 
                                                                    )) === -1 ? true : false
                                                                ))].map(st => ({
                                                                    value: st.Cost_Center_Id,
                                                                    label: st.Cost_Center_Name
                                                                }))
                                                            }
                                                            styles={customSelectStyles}
                                                            isSearchable={true}
                                                            placeholder={"Select Staff"}
                                                        />
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            </div>

                            <div className="col-xxl-10 col-lg-9 col-md-8 py-2 px-0">
                                <div className="border p-2" style={{ minHeight: '30vh', height: '100%' }}>
                                    <div className="d-flex align-items-center flex-wrap mb-2 border-bottom pb-2">
                                        <h6 className="flex-grow-1 my-2 ps-2">Stock Journal Details</h6>
                                    </div>
                                    <div className="row px-2">
                                        <div className="col-xxl-2 col-lg-3 col-md-4 col-sm-6 p-2">
                                            <label>Branch</label>
                                            <select
                                                value={stockJorunalInfo.Branch_Id}
                                                onChange={e => setStockJorunalInfo({ ...stockJorunalInfo, Branch_Id: e.value })}
                                                placeholder={"Select Branch"}
                                                className="cus-inpt "
                                            >
                                                <option value="" disabled>Select Branch</option>
                                                {baseData.branch.map((br, bi) => (
                                                    <option key={bi} value={br.BranchId}>{br.BranchName}</option>
                                                ))}
                                            </select>
                                        </div>
                                        <div className="col-xxl-2 col-lg-3 col-md-4 col-sm-6 p-2">
                                            <label>Date</label>
                                            <input
                                                value={stockJorunalInfo.Stock_Journal_date}
                                                type="date"
                                                onChange={e => setStockJorunalInfo({ ...stockJorunalInfo, Stock_Journal_date: e.target.value })}
                                                className="cus-inpt p-2"
                                            />
                                        </div>
                                        <div className="col-xxl-2 col-lg-3 col-md-4 col-sm-6 p-2">
                                            <label>Bill Type</label>
                                            <select
                                                value={stockJorunalInfo.Stock_Journal_Bill_type}
                                                required
                                                onChange={e => setStockJorunalInfo({ ...stockJorunalInfo, Stock_Journal_Bill_type: e.target.value })}
                                                className="cus-inpt"
                                            >
                                                <option value="" disabled>Select Bill Type</option>
                                                <option value="MATERIAL INWARD">MATERIAL INWARD</option>
                                                <option value="OTHER GODOWN">OTHER GODOWN</option>
                                                <option value="PROCESSING">PROCESSING</option>
                                            </select>
                                        </div>
                                        <div className="col-xxl-2 col-lg-3 col-md-4 col-sm-6 p-2">
                                            <label>Voucher Type</label>
                                            <Select
                                                value={{ value: stockJorunalInfo.Stock_Journal_Voucher_type, label: stockJorunalInfo.Stock_Journal_Voucher_type }}
                                                onChange={e => setStockJorunalInfo({ ...stockJorunalInfo, Stock_Journal_Voucher_type: e.value })}
                                                options={[
                                                    { value: '', label: 'Select Voucher Type', isDisabled: true },
                                                    ...baseData.voucherType.map(vt => ({
                                                        value: vt?.Voucher_Type,
                                                        label: vt?.Voucher_Type
                                                    }))
                                                ]}
                                                styles={customSelectStyles}
                                                isSearchable={true}
                                                placeholder={"Select Voucher Type"}
                                            />
                                        </div>
                                    </div>
                                </div>
                            </div>


                            {/* Source Details */}
                            <div className=" col-xxl-6 p-2 mb-2">
                                <div className="d-flex align-items-center flex-wrap mb-2 border-bottom pb-2">
                                    <h5 className="flex-grow-1 ">Source</h5>
                                    <Button
                                        variant="outlined"
                                        color="primary"
                                        type="button"
                                        onClick={() => setSourceList([...sourceList, { ...initialSoruceValue }])}
                                    >Add</Button>
                                </div>
                                <table className="table table-bordered ">
                                    <thead>
                                        <tr>
                                            <th className="fa-13">Sno</th>
                                            <th className="fa-13">Item</th>
                                            <th className="fa-13">Batch Lot No</th>
                                            <th className="fa-13">Quantity</th>
                                            <th className="fa-13">Unit</th>
                                            <th className="fa-13">Rate</th>
                                            <th className="fa-13">Amount</th>
                                            <th className="fa-13">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {sourceList.map((row, index) => (
                                            <tr key={index}>
                                                <td className='fa-13'>{index + 1}</td>
                                                <td className='fa-13 w-25 p-0'>
                                                    <Select
                                                        value={{ value: row?.Sour_Item_Id, label: row?.Sour_Item_Name }}
                                                        onChange={e => changeSelectedObjects(index, 'Sour_Item_Id', e.value)}
                                                        options={baseData.products.map(pro => ({ value: pro.Product_Id, label: pro.Product_Name }))}
                                                        styles={customSelectStyles}
                                                        isSearchable={true}
                                                        placeholder={"Select Item"}
                                                        maxMenuHeight={300}
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <input
                                                        value={row?.Sour_Batch_Lot_No ?? ""}
                                                        onChange={e => changeSelectedObjects(index, 'Sour_Batch_Lot_No', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <input
                                                        value={row?.Sour_Qty ?? ""}
                                                        type="number"
                                                        min={1}
                                                        required
                                                        onChange={e => changeSelectedObjects(index, 'Sour_Qty', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <select
                                                        value={row?.Sour_Unit_Id ?? ""}
                                                        required
                                                        onChange={e => changeSelectedObjects(index, 'Sour_Unit_Id', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    >
                                                        <option value="" disabled>Select Unit</option>
                                                        {baseData.uom.map((uom, ind) => (
                                                            <option key={ind} value={uom.Unit_Id}>{uom.Units}</option>
                                                        ))}
                                                    </select>
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <input
                                                        value={row?.Sour_Rate ?? ""}
                                                        type="number"
                                                        min={1}
                                                        required
                                                        onChange={e => changeSelectedObjects(index, 'Sour_Rate', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <input
                                                        value={row?.Sour_Amt ?? ""}
                                                        type="number"
                                                        min={1}
                                                        required
                                                        onChange={e => changeSelectedObjects(index, 'Sour_Amt', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 p-0 vctr text-center'>
                                                    <IconButton
                                                        variant="contained"
                                                        color="error"
                                                        type="button"
                                                        size="small"
                                                        onClick={() => setSourceList(sourceList.filter((_, ind) => ind !== index))}
                                                    ><Delete className="fa-20" /></IconButton>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>

                            {/* Destination Entry */}
                            <div className=" col-xxl-6 p-2 mb-2">
                                <div className="d-flex align-items-center flex-wrap mb-2 border-bottom pb-2">
                                    <h5 className="flex-grow-1 ">Destination</h5>
                                    <Button
                                        variant="outlined"
                                        color="primary"
                                        type="button"
                                        onClick={() => setDestinationList([...destinationList, { ...initialDestinationValue }])}
                                    >Add</Button>
                                </div>
                                <table className="table table-bordered ">
                                    <thead>
                                        <tr>
                                            <th className="fa-13">Sno</th>
                                            <th className="fa-13">Item</th>
                                            <th className="fa-13">Batch Lot No</th>
                                            <th className="fa-13">Quantity</th>
                                            <th className="fa-13">Unit</th>
                                            <th className="fa-13">Rate</th>
                                            <th className="fa-13">Amount</th>
                                            <th className="fa-13">Action</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {destinationList.map((row, index) => (
                                            <tr key={index}>
                                                <td className='fa-13'>{index + 1}</td>
                                                <td className='fa-13 w-25 p-0'>
                                                    <Select
                                                        value={{ value: row?.Dest_Item_Id, label: row?.Dest_Item_Name }}
                                                        onChange={e => changeSelectedObjects(index, 'Dest_Item_Id', e.value)}
                                                        options={
                                                            baseData.products.map(pro => ({
                                                                value: pro.Product_Id,
                                                                label: pro.Product_Name
                                                            }))
                                                        }
                                                        styles={customSelectStyles}
                                                        isSearchable={true}
                                                        placeholder={"Select Item"}
                                                        maxMenuHeight={300}
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <input
                                                        value={row?.Dest_Batch_Lot_No ?? ""}
                                                        onChange={e => changeSelectedObjects(index, 'Dest_Batch_Lot_No', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <input
                                                        value={row?.Dest_Qty ?? ""}
                                                        type="number"
                                                        min={1}
                                                        required
                                                        onChange={e => changeSelectedObjects(index, 'Dest_Qty', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <select
                                                        value={row?.Dest_Unit_Id ?? ""}
                                                        required
                                                        onChange={e => changeSelectedObjects(index, 'Dest_Unit_Id', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    >
                                                        <option value="" disabled>Select Unit</option>
                                                        {baseData.uom.map((uom, ind) => (
                                                            <option key={ind} value={uom.Unit_Id}>{uom.Units}</option>
                                                        ))}
                                                    </select>
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <input
                                                        value={row?.Dest_Rate ?? ""}
                                                        type="number"
                                                        min={1}
                                                        required
                                                        onChange={e => changeSelectedObjects(index, 'Dest_Rate', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 vctr'>
                                                    <input
                                                        value={row?.Dest_Amt ?? ""}
                                                        type="number"
                                                        min={1}
                                                        required
                                                        onChange={e => changeSelectedObjects(index, 'Dest_Amt', e.target.value)}
                                                        className="cus-inpt p-2"
                                                    />
                                                </td>
                                                <td className='fa-13 px-1 py-0 p-0 vctr text-center'>
                                                    <IconButton
                                                        variant="contained"
                                                        color="error"
                                                        type="button"
                                                        size="small"
                                                        onClick={() => setDestinationList(destinationList.filter((_, ind) => ind !== index))}
                                                    ><Delete className="fa-20" /></IconButton>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </form>
                </CardContent>
            </Card>
        </>
    )
}

export default StockJournalCreate;